17 | package com.ibm.jp.automation.e2m;
18 | 
19 | import org.w3c.dom.Document;
20 | import org.w3c.dom.Element;
21 | import org.w3c.dom.NodeList;
22 | 
23 | import javax.xml.parsers.DocumentBuilder;
24 | import javax.xml.parsers.DocumentBuilderFactory;
25 | import java.io.IOException;
26 | import java.nio.file.Files;
27 | import java.nio.file.Path;
28 | import java.util.ArrayList;
29 | import java.util.List;
30 | import java.util.Properties;
31 | 
32 | /**
33 |  * Eclipseプロジェクトのメタデータファイルを解析して {@link EclipseProject} を返すパーサー。
34 |  */
35 | public class EclipseProjectParser {
36 | 
37 |     private static final String WTP_NATURE = "org.eclipse.wst.common.project.facet.core.nature";
38 |     private static final String DEFAULT_JAVA_VERSION = "11";
39 | 
40 |     /**
41 |      * 指定した入力ディレクトリを解析して {@link EclipseProject} を返す。
42 |      *
43 |      * @param inputDir Eclipseプロジェクトのルートディレクトリ
44 |      * @return 解析結果
45 |      * @throws Exception 解析中に発生した例外
46 |      */
47 |     public static EclipseProject parse(Path inputDir) throws Exception {
48 |         DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
49 |         DocumentBuilder builder = factory.newDocumentBuilder();
50 | 
51 |         // ── .project ──────────────────────────────────────────────
52 |         Path projectFile = inputDir.resolve(".project");
53 |         // 行頭の空白・改行をスキップするため InputStream 経由でパース
54 |         Document projectDoc = builder.parse(
55 |                 new java.io.ByteArrayInputStream(
56 |                         Files.readString(projectFile).stripLeading().getBytes(java.nio.charset.StandardCharsets.UTF_8)));
57 |         projectDoc.getDocumentElement().normalize();
58 | 
59 |         String projectName = projectDoc.getElementsByTagName("name")
60 |                 .item(0).getTextContent().trim();
61 | 
62 |         boolean webProject = false;
63 |         NodeList natures = projectDoc.getElementsByTagName("nature");
64 |         for (int i = 0; i < natures.getLength(); i++) {
65 |             if (WTP_NATURE.equals(natures.item(i).getTextContent().trim())) {
66 |                 webProject = true;
67 |                 break;
68 |             }
69 |         }
70 | 
71 |         // ── .classpath ────────────────────────────────────────────
72 |         Path classpathFile = inputDir.resolve(".classpath");
73 |         Document cpDoc = builder.parse(classpathFile.toFile());
74 |         cpDoc.getDocumentElement().normalize();
75 | 
76 |         List<String> sourceFolders = new ArrayList<>();
77 |         List<String> jarPaths = new ArrayList<>();
78 |         String outputFolder = null;
79 |         String classpathJavaVersion = DEFAULT_JAVA_VERSION;
80 | 
81 |         NodeList entries = cpDoc.getElementsByTagName("classpathentry");
82 |         for (int i = 0; i < entries.getLength(); i++) {
83 |             Element entry = (Element) entries.item(i);
84 |             String kind = entry.getAttribute("kind");
85 |             String path = entry.getAttribute("path");
86 | 
87 |             switch (kind) {
88 |                 case "src" -> sourceFolders.add(path);
89 |                 case "output" -> outputFolder = path;
90 |                 case "lib" -> jarPaths.add(path);
91 |                 case "con" -> {
92 |                     String version = extractJavaVersion(path);
93 |                     if (version != null) {
94 |                         classpathJavaVersion = version;
95 |                     }
96 |                 }
97 |             }
98 |         }
99 | 
100 |         // ── .settings/org.eclipse.jdt.core.prefs ─────────────────
101 |         // source/target を prefs から取得し、見つからない場合は .classpath の con エントリの値を使う
102 |         String[] versions = parseJdtCorePrefs(inputDir, classpathJavaVersion);
103 |         String javaSourceVersion = versions[0];
104 |         String javaTargetVersion = versions[1];
105 | 
106 |         // ── WTP: .settings/org.eclipse.wst.common.component ──────
107 |         String webContentRoot = null;
108 |         if (webProject) {
109 |             webContentRoot = parseWebContentRoot(inputDir, builder);
110 |         }
111 | 
112 |         return new EclipseProject(
113 |                 projectName,
114 |                 webProject,
115 |                 List.copyOf(sourceFolders),
116 |                 outputFolder,
117 |                 List.copyOf(jarPaths),
118 |                 webContentRoot,
119 |                 javaSourceVersion,
120 |                 javaTargetVersion
121 |         );
122 |     }
123 | 
124 |     /**
125 |      * `.settings/org.eclipse.jdt.core.prefs` を解析して [sourceVersion, targetVersion] を返す。
126 |      * ファイルが存在しない、またはキーが見つからない場合は fallback 値を使用する。
127 |      */
128 |     private static String[] parseJdtCorePrefs(Path inputDir, String fallback) {
129 |         Path prefsFile = inputDir.resolve(".settings")
130 |                 .resolve("org.eclipse.jdt.core.prefs");
131 | 
132 |         if (Files.exists(prefsFile)) {
133 |             Properties props = new Properties();
134 |             try (var reader = Files.newBufferedReader(prefsFile)) {
135 |                 props.load(reader);
136 |                 String source = normalizeJavaVersion(
137 |                         props.getProperty("org.eclipse.jdt.core.compiler.source"));
138 |                 String target = normalizeJavaVersion(
139 |                         props.getProperty("org.eclipse.jdt.core.compiler.codegen.targetPlatform"));
140 |                 // 両方取得できた場合はそのまま使う。片方のみの場合はもう一方も同じ値にする
141 |                 if (source != null && target != null) {
142 |                     return new String[]{source, target};
143 |                 } else if (source != null) {
144 |                     return new String[]{source, source};
145 |                 } else if (target != null) {
146 |                     return new String[]{target, target};
147 |                 }
148 |             } catch (IOException e) {
149 |                 // 読み込み失敗時は fallback を使用
150 |             }
151 |         }
152 | 
153 |         return new String[]{fallback, fallback};
154 |     }
155 | 
156 |     /**
157 |      * "1.8" → "1.8"、"17" → "17" のようにそのまま返す。
158 |      * null や空文字の場合は null を返す。
159 |      */
160 |     private static String normalizeJavaVersion(String value) {
161 |         if (value == null || value.isBlank()) {
162 |             return null;
163 |         }
164 |         return value.trim();
165 |     }
166 | 
167 |     /**
168 |      * `con` エントリの path から Java バージョン番号を抽出する。
169 |      * 例: "...JavaSE-17" → "17", "...java-11-openjdk" → "11"
170 |      */
171 |     private static String extractJavaVersion(String conPath) {
172 |         // JavaSE-XX / java-XX 形式を探す
173 |         int idx = conPath.lastIndexOf('/');
174 |         String segment = (idx >= 0) ? conPath.substring(idx + 1) : conPath;
175 | 
176 |         // JavaSE-XX
177 |         if (segment.contains("JavaSE-")) {
178 |             String after = segment.substring(segment.indexOf("JavaSE-") + "JavaSE-".length());
179 |             String version = after.split("[^0-9.]")[0];
180 |             if (!version.isEmpty()) {
181 |                 return version;
182 |             }
183 |         }
184 | 
185 |         // java-XX (例: java-17-openjdk)
186 |         if (segment.startsWith("java-")) {
187 |             String after = segment.substring("java-".length());
188 |             String version = after.split("[^0-9.]")[0];
189 |             if (!version.isEmpty()) {
190 |                 return version;
191 |             }
192 |         }
193 | 
194 |         return null;
195 |     }
196 | 
197 |     /**
198 |      * `.settings/org.eclipse.wst.common.component` を解析して Webコンテンツルートを返す。
199 |      * ファイルが存在しない場合は null を返す。
200 |      * 先頭の "/" は除去した相対パスとして返す。
201 |      */
202 |     private static String parseWebContentRoot(Path inputDir, DocumentBuilder builder) {
203 |         Path componentFile = inputDir.resolve(".settings")
204 |                 .resolve("org.eclipse.wst.common.component");
205 | 
206 |         if (!Files.exists(componentFile)) {
207 |             return null;
208 |         }
209 | 
210 |         try {
211 |             Document doc = builder.parse(componentFile.toFile());
212 |             doc.getDocumentElement().normalize();
213 | 
214 |             NodeList resources = doc.getElementsByTagName("wb-resource");
215 |             for (int i = 0; i < resources.getLength(); i++) {
216 |                 Element res = (Element) resources.item(i);
217 |                 if ("defaultRootSource".equals(res.getAttribute("tag"))) {
218 |                     String sourcePath = res.getAttribute("source-path");
219 |                     // 先頭の "/" を除去して相対パスに正規化
220 |                     if (sourcePath.startsWith("/")) {
221 |                         sourcePath = sourcePath.substring(1);
222 |                     }
223 |                     return sourcePath;
224 |                 }
225 |             }
226 |         } catch (Exception e) {
227 |             // ファイルが壊れている場合は null を返す
228 |         }
229 | 
230 |         return null;
231 |     }
232 | }
