33 | /**
34 |  * EclipseProject情報と依存関係リストからMavenのpom.xmlを生成するクラス。
35 |  */
36 | public class PomGenerator {
37 | 
38 |     private PomGenerator() {}
39 | 
40 |     /**
41 |      * pom.xmlを生成して出力ディレクトリに保存する。
42 |      *
43 |      * @param eclipseProject パース済みEclipseプロジェクト情報
44 |      * @param dependencies   解決済み依存関係リスト
45 |      * @param groupId        生成するpom.xmlのgroupId
46 |      * @param artifactId     生成するpom.xmlのartifactId
47 |      * @param version        生成するpom.xmlのversion
48 |      * @param outputDir      出力ディレクトリ
49 |      * @throws Exception XML生成またはファイル書き込みに失敗した場合
50 |      */
51 |     public static void generate(
52 |             EclipseProject eclipseProject,
53 |             List<MavenDependency> dependencies,
54 |             String groupId,
55 |             String artifactId,
56 |             String version,
57 |             Path outputDir) throws Exception {
58 | 
59 |         DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
60 |         DocumentBuilder db = dbf.newDocumentBuilder();
61 |         Document doc = db.newDocument();
62 | 
63 |         // <project>
64 |         Element project = doc.createElement("project");
65 |         project.setAttribute("xmlns", "http://maven.apache.org/POM/4.0.0");
66 |         project.setAttribute("xmlns:xsi", "http://www.w3.org/2001/XMLSchema-instance");
67 |         project.setAttribute("xsi:schemaLocation",
68 |                 "http://maven.apache.org/POM/4.0.0 http://maven.apache.org/xsd/maven-4.0.0.xsd");
69 |         doc.appendChild(project);
70 | 
71 |         addTextElement(doc, project, "modelVersion", "4.0.0");
72 |         addTextElement(doc, project, "groupId", groupId);
73 |         addTextElement(doc, project, "artifactId", artifactId);
74 |         addTextElement(doc, project, "version", version);
75 | 
76 |         if (eclipseProject.webProject()) {
77 |             addTextElement(doc, project, "packaging", "war");
78 |         }
79 | 
80 |         // <properties>
81 |         String javaSourceVersion = eclipseProject.javaSourceVersion();
82 |         String javaTargetVersion = eclipseProject.javaTargetVersion();
83 |         Element properties = doc.createElement("properties");
84 |         addTextElement(doc, properties, "project.build.sourceEncoding", "UTF-8");
85 |         addTextElement(doc, properties, "maven.compiler.source", javaSourceVersion);
86 |         addTextElement(doc, properties, "maven.compiler.target", javaTargetVersion);
87 |         project.appendChild(properties);
88 | 
89 |         // <dependencies>
90 |         if (!dependencies.isEmpty()) {
91 |             Element deps = doc.createElement("dependencies");
92 |             for (MavenDependency dep : dependencies) {
93 |                 Element dependency = doc.createElement("dependency");
94 |                 addTextElement(doc, dependency, "groupId", dep.groupId());
95 |                 addTextElement(doc, dependency, "artifactId", dep.artifactId());
96 |                 addTextElement(doc, dependency, "version", dep.version());
97 |                 if (dep.scope() != null && !dep.scope().isEmpty()) {
98 |                     addTextElement(doc, dependency, "scope", dep.scope());
99 |                 }
100 |                 if (dep.systemPath() != null) {
101 |                     addTextElement(doc, dependency, "systemPath", dep.systemPath());
102 |                 }
103 |                 deps.appendChild(dependency);
104 |             }
105 |             project.appendChild(deps);
106 |         }
107 | 
108 |         // <build><plugins><plugin> maven-compiler-plugin
109 |         Element build = doc.createElement("build");
110 |         Element plugins = doc.createElement("plugins");
111 |         Element plugin = doc.createElement("plugin");
112 |         addTextElement(doc, plugin, "groupId", "org.apache.maven.plugins");
113 |         addTextElement(doc, plugin, "artifactId", "maven-compiler-plugin");
114 |         addTextElement(doc, plugin, "version", "3.13.0");
115 |         Element configuration = doc.createElement("configuration");
116 |         addTextElement(doc, configuration, "source", javaSourceVersion);
117 |         addTextElement(doc, configuration, "target", javaTargetVersion);
118 |         plugin.appendChild(configuration);
119 |         plugins.appendChild(plugin);
120 |         build.appendChild(plugins);
121 |         project.appendChild(build);
122 | 
123 |         // XMLをファイルに書き出す
124 |         Files.createDirectories(outputDir);
125 |         TransformerFactory tf = TransformerFactory.newInstance();
126 |         Transformer transformer = tf.newTransformer();
127 |         transformer.setOutputProperty(OutputKeys.INDENT, "yes");
128 |         transformer.setOutputProperty(OutputKeys.ENCODING, "UTF-8");
129 |         transformer.setOutputProperty("{http://xml.apache.org/xslt}indent-amount", "2");
130 | 
131 |         Path pomPath = outputDir.resolve("pom.xml");
132 |         transformer.transform(new DOMSource(doc), new StreamResult(pomPath.toFile()));
133 | 
134 |         System.out.println("Generated: " + pomPath);
135 |     }
136 | 
137 |     private static void addTextElement(Document doc, Element parent, String tagName, String text) {
138 |         Element el = doc.createElement(tagName);
139 |         el.appendChild(doc.createTextNode(text));
140 |         parent.appendChild(el);
141 |     }
142 | }
