31 | class PomGeneratorTest {
32 | 
33 |     @TempDir
34 |     Path tempDir;
35 | 
36 |     private EclipseProject javaProject() {
37 |         return new EclipseProject("MyApp", false, List.of("src"), "bin",
38 |                 List.of(), null, "17", "17");
39 |     }
40 | 
41 |     private EclipseProject webProject() {
42 |         return new EclipseProject("MyWebApp", true, List.of("src"), "build/classes",
43 |                 List.of(), "WebContent", "11", "1.8");
44 |     }
45 | 
46 |     private Document parsePom() throws Exception {
47 |         DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
48 |         DocumentBuilder db = dbf.newDocumentBuilder();
49 |         return db.parse(tempDir.resolve("pom.xml").toFile());
50 |     }
51 | 
52 |     @Test
53 |     void javaProject_noPackagingElement() throws Exception {
54 |         PomGenerator.generate(javaProject(), List.of(), "com.example", "myapp", "1.0", tempDir);
55 |         Document doc = parsePom();
56 |         NodeList packaging = doc.getElementsByTagName("packaging");
57 |         assertEquals(0, packaging.getLength(), "<packaging> 要素はJavaプロジェクトでは省略される");
58 |     }
59 | 
60 |     @Test
61 |     void javaProject_coordinates() throws Exception {
62 |         PomGenerator.generate(javaProject(), List.of(), "com.example", "myapp", "2.0", tempDir);
63 |         Document doc = parsePom();
64 |         assertEquals("com.example", doc.getElementsByTagName("groupId").item(0).getTextContent());
65 |         assertEquals("myapp", doc.getElementsByTagName("artifactId").item(0).getTextContent());
66 |         assertEquals("2.0", doc.getElementsByTagName("version").item(0).getTextContent());
67 |     }
68 | 
69 |     @Test
70 |     void webProject_hasWarPackaging() throws Exception {
71 |         PomGenerator.generate(webProject(), List.of(), "com.example", "webapp", "1.0", tempDir);
72 |         Document doc = parsePom();
73 |         NodeList packaging = doc.getElementsByTagName("packaging");
74 |         assertEquals(1, packaging.getLength());
75 |         assertEquals("war", packaging.item(0).getTextContent());
76 |     }
77 | 
78 |     @Test
79 |     void javaSourceVersion_reflectedInProperties() throws Exception {
80 |         PomGenerator.generate(javaProject(), List.of(), "com.example", "myapp", "1.0", tempDir);
81 |         Document doc = parsePom();
82 |         NodeList props = doc.getElementsByTagName("maven.compiler.source");
83 |         assertEquals(1, props.getLength());
84 |         assertEquals("17", props.item(0).getTextContent());
85 |     }
86 | 
87 |     @Test
88 |     void javaTargetVersion_reflectedInProperties() throws Exception {
89 |         PomGenerator.generate(javaProject(), List.of(), "com.example", "myapp", "1.0", tempDir);
90 |         Document doc = parsePom();
91 |         NodeList props = doc.getElementsByTagName("maven.compiler.target");
92 |         assertEquals(1, props.getLength());
93 |         assertEquals("17", props.item(0).getTextContent());
94 |     }
95 | 
96 |     @Test
97 |     void sourceAndTargetCanDiffer() throws Exception {
98 |         PomGenerator.generate(webProject(), List.of(), "com.example", "webapp", "1.0", tempDir);
99 |         Document doc = parsePom();
100 |         assertEquals("11", doc.getElementsByTagName("maven.compiler.source").item(0).getTextContent());
101 |         assertEquals("1.8", doc.getElementsByTagName("maven.compiler.target").item(0).getTextContent());
102 |     }
103 | 
104 |     @Test
105 |     void dependency_centralFound_noScope() throws Exception {
106 |         MavenDependency dep = new MavenDependency("org.apache.commons", "commons-lang3", "3.12.0", null, null);
107 |         PomGenerator.generate(javaProject(), List.of(dep), "com.example", "myapp", "1.0", tempDir);
108 |         Document doc = parsePom();
109 | 
110 |         NodeList groupIds = doc.getElementsByTagName("groupId");
111 |         // 最初はprojectのgroupId、2番目がdependencyのgroupId
112 |         boolean found = false;
113 |         for (int i = 0; i < groupIds.getLength(); i++) {
114 |             if ("org.apache.commons".equals(groupIds.item(i).getTextContent())) {
115 |                 found = true;
116 |             }
117 |         }
118 |         assertTrue(found, "依存のgroupIdが出力される");
119 |         // scopeは出力されない
120 |         NodeList scopes = doc.getElementsByTagName("scope");
121 |         assertEquals(0, scopes.getLength(), "スコープなしの依存にscope要素は不要");
122 |     }
123 | 
124 |     @Test
125 |     void dependency_systemScope_hasScopeAndSystemPath() throws Exception {
126 |         MavenDependency dep = new MavenDependency("mylib", "mylib", "0.0.0", "system", "/opt/libs/mylib.jar");
127 |         PomGenerator.generate(javaProject(), List.of(dep), "com.example", "myapp", "1.0", tempDir);
128 |         Document doc = parsePom();
129 | 
130 |         NodeList scopes = doc.getElementsByTagName("scope");
131 |         assertEquals(1, scopes.getLength());
132 |         assertEquals("system", scopes.item(0).getTextContent());
133 | 
134 |         NodeList systemPaths = doc.getElementsByTagName("systemPath");
135 |         assertEquals(1, systemPaths.getLength());
136 |         assertEquals("/opt/libs/mylib.jar", systemPaths.item(0).getTextContent());
