27 | /**
28 |  * {@link EclipseProjectParser} のユニットテスト。
29 |  */
30 | class EclipseProjectParserTest {
31 | 
32 |     /** テストリソースのルートパスを取得するヘルパー。 */
33 |     private Path resourceDir(String name) throws Exception {
34 |         URL url = getClass().getClassLoader().getResource(name);
35 |         assertNotNull(url, "テストリソースが見つかりません: " + name);
36 |         return Paths.get(url.toURI());
37 |     }
38 | 
39 |     // ─────────────────────────────────────────────────────────────
40 |     // 通常の Java プロジェクト
41 |     // ─────────────────────────────────────────────────────────────
42 | 
